// ============================================
// HAMBURGER / MOBILE MENU
// ============================================
var hamburger   = document.getElementById('hamburger');
var mobileMenu  = document.getElementById('mobileMenu');
var menuOverlay = document.getElementById('menuOverlay');

function openMobileMenu() {
  hamburger.classList.add('active');
  hamburger.setAttribute('aria-expanded', 'true');
  mobileMenu.classList.add('open');
  mobileMenu.removeAttribute('aria-hidden');
  if (menuOverlay) menuOverlay.classList.add('active');
  document.body.classList.add('menu-open');
}

function closeMobileMenu() {
  hamburger.classList.remove('active');
  hamburger.setAttribute('aria-expanded', 'false');
  mobileMenu.classList.remove('open');
  mobileMenu.setAttribute('aria-hidden', 'true');
  if (menuOverlay) menuOverlay.classList.remove('active');
  document.body.classList.remove('menu-open');
}

if (hamburger) {
  hamburger.addEventListener('click', function() {
    if (mobileMenu.classList.contains('open')) {
      closeMobileMenu();
    } else {
      openMobileMenu();
    }
  });
}

// Close on nav link click
document.querySelectorAll('.mobile-link').forEach(function(link) {
  link.addEventListener('click', closeMobileMenu);
});

// Close on overlay click
if (menuOverlay) {
  menuOverlay.addEventListener('click', closeMobileMenu);
}

// Close on Escape key
document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape' && mobileMenu && mobileMenu.classList.contains('open')) {
    closeMobileMenu();
  }
});

// Close menu on resize to desktop
window.addEventListener('resize', function() {
  if (window.innerWidth >= 769) {
    closeMobileMenu();
  }
}, { passive: true });

// ============================================
// TYPEWRITER
// ============================================
var phrases = [
  'From real estate recovery to field sales — we engineer the systems that power Asia\'s most ambitious enterprises.',
  'Trusted by 500+ clients across Pakistan, UAE, Saudi Arabia and beyond.',
  'Purpose-built ERP for real estate, textile, distribution and logistics.',
  'Engineered in New York · Dubai · Karachi.'
];
var phraseIndex = 0, charIndex = 0, isDeleting = false;
var typeEl = document.getElementById('typewriter');

function typewrite() {
  var current = phrases[phraseIndex];
  if (isDeleting) {
    charIndex--;
    typeEl.textContent = current.slice(0, charIndex);
  } else {
    charIndex++;
    typeEl.textContent = current.slice(0, charIndex);
  }
  var delay = isDeleting ? 30 : 55;
  if (!isDeleting && charIndex === current.length) {
    delay = 2200;
    isDeleting = true;
  } else if (isDeleting && charIndex === 0) {
    isDeleting = false;
    phraseIndex = (phraseIndex + 1) % phrases.length;
    delay = 400;
  }
  setTimeout(typewrite, delay);
}
setTimeout(typewrite, 1600);

