// ============================================
// FOOTER PEEK — tap-toggle & outside-click close
// ============================================
(function() {
  var footerEl   = document.getElementById('siteFooter');
  var footerPeek = document.getElementById('footerPeek');
  if (!footerEl || !footerPeek) return;

  footerPeek.addEventListener('click', function(e) {
    e.stopPropagation();
    var isOpen = footerEl.classList.toggle('is-open');
    footerPeek.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
  });

  document.addEventListener('click', function(e) {
    if (!footerEl.classList.contains('is-open')) return;
    if (footerEl.contains(e.target)) return;
    footerEl.classList.remove('is-open');
    footerPeek.setAttribute('aria-expanded', 'false');
  });

  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape' && footerEl.classList.contains('is-open')) {
      footerEl.classList.remove('is-open');
      footerPeek.setAttribute('aria-expanded', 'false');
    }
  });
})();

